235	function isGraphQLEndpoint(input: Parameters<typeof globalThis.fetch>[0]): boolean {
236		if (typeof input === 'string') {
237			return new URL(input, globalThis.location?.href ?? 'http://localhost').pathname === '/graphql';
238		}
239		if (input instanceof URL) {
240			return input.pathname === '/graphql';
241		}
242		return new URL(input.url).pathname === '/graphql';
243	}
244	
245	async function requestBodyText(
246		input: Parameters<typeof globalThis.fetch>[0],
247		init?: Parameters<typeof globalThis.fetch>[1]
248	): Promise<string | null> {
249		if (typeof init?.body === 'string') {
250			return init.body;
251		}
252		if (input instanceof Request) {
253			return input.clone().text();
254		}
255		return null;
256	}
257	
258	function fallbackGraphQLResponse(data: object): Response {
259		return new Response(JSON.stringify({ data }), {
260			status: 200,
261			headers: { 'content-type': 'application/json' }
262		});
263	}
264	
265	function delegateInputFor(
266		input: Parameters<typeof globalThis.fetch>[0]
267	): Parameters<typeof globalThis.fetch>[0] {
268		if (typeof window === 'undefined' || !isGraphQLEndpoint(input)) {
269			return input;
270		}
271		if (typeof input === 'string' || input instanceof URL) {
272			return '/graphql';
273		}
274		return input;
275	}
276	
277	function withStaticPreviewFallback(fetchFn?: typeof globalThis.fetch): typeof globalThis.fetch {
278		const delegate = fetchFn ?? globalThis.fetch;
279		return async (input, init) => {
280			const delegateInput = delegateInputFor(input);
281			const response = await delegate(delegateInput, init);
282			if (response.status !== 404 || !isGraphQLEndpoint(input)) {
283				return response;
284			}
285	
286			const bodyText = await requestBodyText(input, init);
287			if (!bodyText) {
288				return response;
289			}
290	
291			let body: { query?: string };
292			try {
293				body = JSON.parse(bodyText) as { query?: string };
294			} catch {
295				return response;
296			}
297	
298			const data = body.query ? fallbackDataForQuery(body.query) : null;
299			return data ? fallbackGraphQLResponse(data) : response;
300		};
301	}
302	
303	/**
304	 * Creates a GraphQL HTTP client for queries and mutations.
305	 *
306	 * Pass the SvelteKit-provided `fetch` in load functions so requests
307	 * respect SvelteKit's SSR/CSR fetch instrumentation.
308	 */
309	export function createClient(fetchFn?: typeof globalThis.fetch): GraphQLClient {
310		const url =
311			typeof window !== 'undefined' ? new URL('/graphql', window.location.href).href : '/graphql';
312		return new GraphQLClient(url, { fetch: withStaticPreviewFallback(fetchFn) });
313	}
