5	const EXECUTIONS_QUERY = gql`
6		query ExecutionsPage(
7			$projectId: ID!
8			$first: Int
9			$after: String
10			$beadId: String
11			$verdict: String
12			$harness: String
13			$search: String
14		) {
15			executions(
16				projectId: $projectId
17				first: $first
18				after: $after
19				beadId: $beadId
20				verdict: $verdict
21				harness: $harness
22				search: $search
23			) {
24				edges {
25					node {
26						id
27						projectId
28						beadId
29						beadTitle
30						sessionId
31						harness
32						model
33						verdict
34						status
35						createdAt
36						startedAt
37						finishedAt
38						durationMs
39						costUsd
40						tokens
41						exitCode
42						bundlePath
43					}
44					cursor
45				}
46				pageInfo {
47					hasNextPage
48					hasPreviousPage
49					startCursor
50					endCursor
51				}
52				totalCount
53			}
54		}
55	`;
