57	export interface ExecutionListNode {
58		id: string;
59		projectId: string;
60		beadId: string | null;
61		beadTitle: string | null;
62		sessionId: string | null;
63		harness: string | null;
64		model: string | null;
65		verdict: string | null;
66		status: string | null;
67		createdAt: string;
68		startedAt: string | null;
69		finishedAt: string | null;
70		durationMs: number | null;
71		costUsd: number | null;
72		tokens: number | null;
