99	const PAGE_SIZE = 50;
100	
101	export const load: PageLoad = async ({ params, url, fetch }) => {
102		const after = url.searchParams.get('after') ?? undefined;
103		const beadId = url.searchParams.get('bead') ?? undefined;
104		const verdict = url.searchParams.get('verdict') ?? undefined;
105		const harness = url.searchParams.get('harness') ?? undefined;
106		const search = url.searchParams.get('q') ?? undefined;
107	
108		const client = createClient(fetch as unknown as typeof globalThis.fetch);
109		const data = await client.request<ExecutionsResult>(EXECUTIONS_QUERY, {
110			projectId: params.projectId,
111			first: PAGE_SIZE,
112			after,
113			beadId,
114			verdict,
115			harness,
116			search
117		});
118		return {
119			nodeId: params.nodeId,
120			projectId: params.projectId,
121			executions: data.executions,
122			filters: {
123				after: after ?? null,
124				bead: beadId ?? '',
125				verdict: verdict ?? '',
126				harness: harness ?? '',
127				search: search ?? ''
128			}
129		};
130	};
