1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { goto } from '$app/navigation';
4		import type { ExecutionListNode } from './+page';
5	
6		let { data }: { data: PageData } = $props();
7	
8		let bead = $state(data.filters.bead);
9		let verdict = $state(data.filters.verdict);
10		let harness = $state(data.filters.harness);
11		let search = $state(data.filters.search);
12	
13		function applyFilters() {
14			const params = new URLSearchParams();
15			if (bead) params.set('bead', bead);
16			if (verdict) params.set('verdict', verdict);
17			if (harness) params.set('harness', harness);
18			if (search) params.set('q', search);
19			const qs = params.toString();
20			goto(
21				`/nodes/${data.nodeId}/projects/${data.projectId}/executions${qs ? `?${qs}` : ''}`,
22				{ keepFocus: true, noScroll: true }
23			);
24		}
25	
26		function clearFilters() {
27			bead = '';
28			verdict = '';
29			harness = '';
30			search = '';
31			applyFilters();
32		}
33	
34		function detailHref(id: string): string {
35			return `/nodes/${data.nodeId}/projects/${data.projectId}/executions/${id}`;
36		}
37	
38		function beadHref(beadId: string): string {
39			return `/nodes/${data.nodeId}/projects/${data.projectId}/beads/${beadId}`;
40		}
41	
42		function fmtDuration(ms: number | null): string {
43			if (ms == null) return '—';
44			if (ms < 1000) return `${ms}ms`;
45			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`;
46			const m = Math.floor(ms / 60_000);
47			const s = Math.floor((ms % 60_000) / 1000);
48			return `${m}m ${s}s`;
49		}
50	
51		function fmtCost(c: number | null): string {
52			if (c == null) return '—';
53			return `$${c.toFixed(4)}`;
54		}
55	
56		function fmtDate(iso: string | null): string {
57			if (!iso) return '—';
58			return new Date(iso).toLocaleString();
59		}
60	
61		function verdictClass(v: string | null): string {
62			const lc = (v ?? '').toLowerCase();
63			if (lc === 'pass' || lc === 'success' || lc === 'task_succeeded') {
64				return 'badge-status-closed';
65			}
66			if (lc === 'block' || lc === 'failure' || lc === 'task_failed') {
67				return 'badge-status-failed';
68			}
69			if (lc === 'no_changes' || lc === 'task_no_changes') {
70				return 'badge-status-in-progress';
71			}
72			return 'badge-status-open';
73		}
74	
75		function goNext() {
76			const cursor = data.executions.pageInfo.endCursor;
77			if (!cursor) return;
78			const params = new URLSearchParams();
79			if (bead) params.set('bead', bead);
80			if (verdict) params.set('verdict', verdict);
81			if (harness) params.set('harness', harness);
82			if (search) params.set('q', search);
83			params.set('after', cursor);
84			goto(`/nodes/${data.nodeId}/projects/${data.projectId}/executions?${params.toString()}`);
85		}
86	
87		function goPrev() {
88			const params = new URLSearchParams();
89			if (bead) params.set('bead', bead);
90			if (verdict) params.set('verdict', verdict);
91			if (harness) params.set('harness', harness);
92			if (search) params.set('q', search);
93			const qs = params.toString();
94			goto(`/nodes/${data.nodeId}/projects/${data.projectId}/executions${qs ? `?${qs}` : ''}`);
95		}
96	
97		const rows = $derived(data.executions.edges.map((e: { node: ExecutionListNode }) => e.node));
98	</script>
