1	package graphql
2	
3	import (
4		"context"
5		"strings"
6	)
7	
8	// RunsStateProvider is the optional sub-interface a StateProvider may
9	// implement to back the runs/run queries.
10	// Kept separate from StateProvider so test stubs that don't need runs
11	// continue to compile.
12	type RunsStateProvider interface {
13		GetRunsGraphQL(projectID string, filter RunFilter) []*Run
14		GetRunGraphQL(id string) (*Run, bool)
15	}
16	
17	// RunFilter holds the optional filter args for Query.runs.
18	type RunFilter struct {
19		Layer   *RunLayer
20		BeadID  string
21		Status  string
22		Harness string
23	}
24	
25	// Runs is the resolver for the runs field.
26	func (r *queryResolver) Runs(ctx context.Context, projectID *string, layer *RunLayer, beadID *string, status *string, harness *string, first *int, after *string) (*RunConnection, error) {
27		provider, ok := r.State.(RunsStateProvider)
28		if !ok {
29			return emptyRunConnection(), nil
30		}
31		pid := ""
32		if projectID != nil {
33			pid = *projectID
34		}
35		filter := RunFilter{Layer: layer}
36		if beadID != nil {
37			filter.BeadID = *beadID
38		}
39		if status != nil {
40			filter.Status = *status
41		}
42		if harness != nil {
43			filter.Harness = *harness
44		}
45		all := provider.GetRunsGraphQL(pid, filter)
46		return runConnectionFrom(all, first, after), nil
47	}
48	
49	// Run is the resolver for the run field.
50	func (r *queryResolver) Run(ctx context.Context, id string) (*Run, error) {
51		provider, ok := r.State.(RunsStateProvider)
52		if !ok {
53			return nil, nil
54		}
55		run, ok := provider.GetRunGraphQL(id)
56		if !ok {
57			return nil, nil
58		}
59		return run, nil
60	}
61	
62	func emptyRunConnection() *RunConnection {
63		return &RunConnection{Edges: []*RunEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
64	}
65	
66	func runConnectionFrom(runs []*Run, first *int, after *string) *RunConnection {
67		all := make([]*RunEdge, len(runs))
68		ids := make([]string, len(runs))
69		for i, r := range runs {
70			all[i] = &RunEdge{Node: r, Cursor: encodeStableCursor(r.ID)}
71			ids[i] = r.ID
72		}
73		startIdx, _ := stablePageBounds(ids, after, nil)
74		slice := all[startIdx:]
75		truncByFirst := false
76		if first != nil && *first >= 0 && *first < len(slice) {
77			slice = slice[:*first]
78			truncByFirst = true
79		}
80		pageInfo := &PageInfo{
81			HasPreviousPage: startIdx > 0,
82			HasNextPage:     truncByFirst,
83		}
84		if len(slice) > 0 {
85			pageInfo.StartCursor = &slice[0].Cursor
86			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
87		}
88		return &RunConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
89	}
90	
91	// ApplyRunFilter applies the filter to a list of runs. Exported so state_runs.go can call it.
92	func ApplyRunFilter(in []*Run, filter RunFilter) []*Run {
93		return applyRunFilter(in, filter)
94	}
95	
96	// applyRunFilter applies the filter to a list of runs.
97	func applyRunFilter(in []*Run, filter RunFilter) []*Run {
98		if len(in) == 0 {
99			return in
100		}
101		if filter.Layer == nil && filter.BeadID == "" && filter.Status == "" && filter.Harness == "" {
102			return in
103		}
104		out := in[:0:0]
105		for _, r := range in {
106			if filter.Layer != nil && r.Layer != *filter.Layer {
107				continue
108			}
109			if filter.BeadID != "" {
110				if r.BeadID == nil || *r.BeadID != filter.BeadID {
111					continue
112				}
113			}
114			if filter.Status != "" {
115				if !strings.EqualFold(r.Status, filter.Status) {
116					continue
117				}
118			}
119			if filter.Harness != "" {
120				if r.Harness == nil || *r.Harness != filter.Harness {
121					continue
122				}
123			}
124			out = append(out, r)
125		}
126		return out
127	}
