340	// TestRunFilter_LayerFilter covers applyRunFilter edge cases.
341	func TestRunFilter_LayerFilter(t *testing.T) {
342		work := ddxgraphql.RunLayerWork
343		try := ddxgraphql.RunLayerTry
344		run := ddxgraphql.RunLayerRun
345	
346		runs := []*ddxgraphql.Run{
347			makeRun("work-001", ddxgraphql.RunLayerWork, "success"),
348			makeRun("try-001", ddxgraphql.RunLayerTry, "success"),
349			makeRun("run-001", ddxgraphql.RunLayerRun, "success"),
350			makeRunWithHarness("run-002", ddxgraphql.RunLayerRun, "failure", "codex"),
351		}
352	
353		cases := []struct {
354			name    string
355			filter  ddxgraphql.RunFilter
356			wantLen int
357			wantIDs []string
358		}{
359			{"no filter", ddxgraphql.RunFilter{}, 4, nil},
360			{"layer=work", ddxgraphql.RunFilter{Layer: &work}, 1, []string{"work-001"}},
361			{"layer=try", ddxgraphql.RunFilter{Layer: &try}, 1, []string{"try-001"}},
362			{"layer=run", ddxgraphql.RunFilter{Layer: &run}, 2, nil},
363			{"status=failure", ddxgraphql.RunFilter{Status: "failure"}, 1, []string{"run-002"}},
364			{"status=success", ddxgraphql.RunFilter{Status: "success"}, 3, nil},
365			{"harness=claude", ddxgraphql.RunFilter{Harness: "claude"}, 1, []string{"run-001"}},
366		}
367	
368		for _, tc := range cases {
369			t.Run(tc.name, func(t *testing.T) {
370				got := ddxgraphql.ApplyRunFilter(runs, tc.filter)
371				if len(got) != tc.wantLen {
372					t.Fatalf("filter %q: expected %d runs, got %d", tc.name, tc.wantLen, len(got))
373				}
374				for _, wantID := range tc.wantIDs {
375					found := false
376					for _, r := range got {
377						if r.ID == wantID {
378							found = true
379							break
380						}
381					}
382					if !found {
383						t.Fatalf("filter %q: expected run %q in result", tc.name, wantID)
384					}
385				}
386			})
387		}
388	}
