302	// loadRunsForProject loads runs for a single project, merging the file store
303	// with synthesized execution bundle records.
304	func (s *ServerState) loadRunsForProject(projectID, projectRoot string) []*ddxgraphql.Run {
305		// Primary: FEAT-010 run store
306		stored := scanRunStore(projectRoot)
307	
308		// Secondary: synthesize run-layer records from .ddx/executions/ bundles,
309		// but only include IDs that are not already in the stored set.
310		storedIDs := make(map[string]bool, len(stored))
311		for _, r := range stored {
312			storedIDs[r.ID] = true
313		}
314	
315		synthesized := synthesizeRunsFromBundles(projectID, projectRoot)
316		for _, r := range synthesized {
317			if !storedIDs[r.ID] {
318				stored = append(stored, r)
319			}
320		}
321	
322		// Sort newest-first by startedAt.
323		sort.Slice(stored, func(i, j int) bool {
324			si, sj := "", ""
325			if stored[i].StartedAt != nil {
326				si = *stored[i].StartedAt
327			}
328			if stored[j].StartedAt != nil {
329				sj = *stored[j].StartedAt
330			}
331			return si > sj
332		})
333		return stored
334	}
