337	func (s *ServerState) GetRunGraphQL(id string) (*ddxgraphql.Run, bool) {
338		if id == "" {
339			return nil, false
340		}
341		// Search all projects.
342		for _, proj := range s.GetProjects(false) {
343			runs := s.loadRunsForProject(proj.ID, proj.Path)
344			for _, r := range runs {
345				if r.ID == id {
346					return r, true
347				}
348			}
349		}
350		return nil, false
351	}
